1	/** A live cell's position on an infinite grid, expressed as [x, y] coordinates. */
2	export type Cell = [number, number];
3	
4	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
5	  [-1, -1], [-1, 0], [-1, 1],
6	  [ 0, -1],          [ 0, 1],
7	  [ 1, -1], [ 1, 0], [ 1, 1],
8	];
9	
10	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
11	
12	const survivesOrIsBorn = (wasAlive: boolean, liveNeighbors: number): boolean =>
13	  liveNeighbors === 3 || (wasAlive && liveNeighbors === 2);
14	
15	/**
16	 * Applies Conway's Game of Life rules to the given live cells and returns
17	 * the next generation. Dead cells are implicit: any coordinate not listed is dead.
18	 *
19	 * Single-pass strategy: for each live cell, increment a neighbor-count for each
20	 * of its 8 surrounding positions. A position appears in the next generation when
21	 * it has exactly 3 live neighbors, or it was alive and has exactly 2.
22	 */
23	export function nextGeneration(liveCells: Cell[]): Cell[] {
24	  const livingKeys = new Set(liveCells.map(cellKey));
25	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
26	  for (const [x, y] of liveCells) {
27	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
28	      const neighbor: Cell = [x + dx, y + dy];
29	      const key = cellKey(neighbor);
30	      const existing = neighborCounts.get(key);
31	      if (existing) {
32	        existing.count++;
33	      } else {
34	        neighborCounts.set(key, { cell: neighbor, count: 1 });
35	      }
36	    }
37	  }
38	  const survivors: Cell[] = [];
39	  for (const [key, { cell, count }] of neighborCounts) {
40	    if (survivesOrIsBorn(livingKeys.has(key), count)) {
41	      survivors.push(cell);
42	    }
43	  }
44	  return survivors;
45	}
